// Get existing records from the Read node — may be empty/failed if file didn't exist
let existingRecords = [];

const readNodeOutput = $('Read/Write Files from Disk').first();

if (readNodeOutput && readNodeOutput.binary && readNodeOutput.binary.data) {
  try {
    const fileText = Buffer.from(readNodeOutput.binary.data.data, 'base64').toString('utf8');
    existingRecords = fileText.trim() ? JSON.parse(fileText) : [];
  } catch (e) {
    existingRecords = [];
  }
}

// Build the new CRM record from Edit Fields1's output
const source = $('Edit Fields1').item.json;

const newRecord = {
  crm_record_id: source.crm_record_id,
  created_at: source.created_at,
  status: source.status,
  company_name: source.company_name,
  contact_name: source.contact_name,
  contact_email: source.contact_email,
  contact_phone: source.contact_phone,
  product_interest: source.product_interest,
  quantity: source.quantity,
  project_location: source.project_location,
  deadline: source.deadline,
  attachments: source.attachments,
  extracted_intent: source.extracted_intent,
};

existingRecords.push(newRecord);

return [{
  json: newRecord,
  binary: {
    data: {
      data: Buffer.from(JSON.stringify(existingRecords, null, 2)).toString('base64'),
      mimeType: 'application/json',
      fileName: 'mock_crm.json',
    }
  }
}];

