let alerts = [];
const readNodeOutput = $('Read Alerts File').first();

if (readNodeOutput && readNodeOutput.binary && readNodeOutput.binary.data) {
  try {
    const fileText = Buffer.from(readNodeOutput.binary.data.data, 'base64').toString('utf8');
    alerts = fileText.trim() ? JSON.parse(fileText) : [];
  } catch (e) {
    alerts = [];
  }
}

const source = $('Edit Fields').item.json;

let parsedReply = { reply_en: null, reply_ar: null };
try {
  const replyText = $('Message a model1').item.json.output[0].content[0].text;
  parsedReply = JSON.parse(replyText);
} catch (e) {
  parsedReply = { reply_en: null, reply_ar: null };
}

const newAlert = {
  alert_id: `alert-${Date.now()}`,
  triggered_at: new Date().toISOString(),
  type: 'new_rfq_received',
  message: `New RFQ from ${source.company_name} (${source.contact_name}) — ${source.quantity} units of ${source.product_interest}`,
  crm_record_id: $('Edit Fields1').item.json.crm_record_id,
  draft_reply_en: parsedReply.reply_en,
  draft_reply_ar: parsedReply.reply_ar,
};

alerts.push(newAlert);

return [{
  json: newAlert,
  binary: {
    data: {
      data: Buffer.from(JSON.stringify(alerts, null, 2)).toString('base64'),
      mimeType: 'application/json',
      fileName: 'alerts.json',
    }
  }
}];
